package com.guardian.net

import android.app.KeyguardManager
import android.content.Context
import android.graphics.PixelFormat
import android.view.Gravity
import android.view.WindowManager
import android.widget.FrameLayout
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.material3.Icon
import androidx.compose.material3.Text
import androidx.compose.runtime.Composable
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Brush
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.ComposeView
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.text.style.TextAlign
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import androidx.lifecycle.*
import androidx.savedstate.SavedStateRegistry
import androidx.savedstate.SavedStateRegistryOwner
import androidx.savedstate.setViewTreeSavedStateRegistryOwner

object DungeonOverlayManager : LifecycleOwner, SavedStateRegistryOwner {
    private var windowManager: WindowManager? = null
    private var overlayView: FrameLayout? = null
    private val lifecycleRegistry = LifecycleRegistry(this)
    private val savedStateRegistryController = SavedStateRegistryController.create(this)

    override val lifecycle: Lifecycle = lifecycleRegistry
    override val savedStateRegistry: SavedStateRegistry = savedStateRegistryController.savedStateRegistry

    fun show(ctx: Context, type: String) {
        val km = ctx.getSystemService(Context.KEYGUARD_SERVICE) as KeyguardManager
        if (overlayView != null || km.isKeyguardLocked) return

        lifecycleRegistry.currentState = Lifecycle.State.CREATED
        savedStateRegistryController.performRestore(null)
        lifecycleRegistry.currentState = Lifecycle.State.RESUMED

        windowManager = ctx.getSystemService(Context.WINDOW_SERVICE) as WindowManager
        val params = WindowManager.LayoutParams().apply {
            type = WindowManager.LayoutParams.TYPE_ACCESSIBILITY_OVERLAY
            format = PixelFormat.TRANSLUCENT
            // FLAG_NOT_FOCUSABLE allows swiping notification shade and using Nav Bar
            flags = WindowManager.LayoutParams.FLAG_NOT_FOCUSABLE or 
                    WindowManager.LayoutParams.FLAG_LAYOUT_IN_SCREEN or
                    WindowManager.LayoutParams.FLAG_NOT_TOUCH_MODAL
            width = WindowManager.LayoutParams.MATCH_PARENT
            height = WindowManager.LayoutParams.MATCH_PARENT
            gravity = Gravity.CENTER
        }

        overlayView = FrameLayout(ctx).apply {
            val composeView = ComposeView(ctx).apply {
                setViewTreeLifecycleOwner(this@DungeonOverlayManager)
                setViewTreeSavedStateRegistryOwner(this@DungeonOverlayManager)
                setContent {
                    GhostContent(type)
                }
            }
            addView(composeView)
        }

        try {
            windowManager?.addView(overlayView, params)
        } catch (e: Exception) { e.printStackTrace() }
    }

    @Composable
    fun GhostContent(type: String) {
        val config = SharedLockdownUI.getUiConfig(type)
        Box(modifier = Modifier.fillMaxSize().background(Color.Black.copy(alpha = 0.95f))) {
            Column(
                modifier = Modifier.fillMaxSize().padding(32.dp),
                verticalArrangement = Arrangement.Center,
                horizontalAlignment = Alignment.CenterHorizontally
            ) {
                Icon(config.icon, null, modifier = Modifier.size(64.dp), tint = config.color)
                Spacer(modifier = Modifier.height(24.dp))
                Text(config.title, color = Color.White, fontSize = 24.sp, fontWeight = FontWeight.Bold, textAlign = TextAlign.Center)
                Spacer(modifier = Modifier.height(8.dp))
                Text(config.description, color = Color.LightGray, fontSize = 14.sp, textAlign = TextAlign.Center)
                Spacer(modifier = Modifier.height(40.dp))
                Text("FIX PERMISSIONS TO UNLOCK", color = config.color, fontWeight = FontWeight.Black, fontSize = 12.sp)
            }
        }
    }

    fun hide() {
        overlayView?.let {
            try { windowManager?.removeView(it) } catch (e: Exception) {}
            overlayView = null
            lifecycleRegistry.currentState = Lifecycle.State.DESTROYED
        }
    }
}

